<?php
include_once __DIR__ . '/koneksi.php';

if (isset($_POST['login'])) {
  $username = $_POST['username'];
  $password = md5($_POST['password']);
  $role = $_POST['role'];

  $query = mysqli_query($koneksi, "select*from user where username='$username' and password='$password' and role=$role and status=1");

  if (mysqli_num_rows($query) > 0) {
    $_SESSION['user'] = mysqli_fetch_array($query);
    $_SESSION['role'] = $role;

    echo '<div class="alert alert-success">Congratulations you have successfully logged in.</div>';
    echo '<meta http-equiv="refresh" content="1;url=index.php">';
  } else {

    echo '<div class="alert alert-danger">Incorrect username or password.</div>';
  }
}
?>

